class Solution(object):
    def incremovableSubarrayCount(self, nums):
        n = len(nums)
        count = 0
        for i in range(n):
            for j in range(i, n):
                remaining = nums[:i] + nums[j + 1:]
                ok = all(remaining[k] < remaining[k + 1] for k in range(len(remaining) - 1))
                if ok:
                    count += 1
        return count
